// background.js
class CookieBannerAI {
  constructor() {
    this.isInitialized = false;
    this.commonPatterns = this.loadCommonPatterns();
  }

  async initialize() {
    if (this.isInitialized) return;

    try {
      // Initialize lightweight AI model or API connection
      console.log('Initializing Cookie Banner AI...');
      this.isInitialized = true;
    } catch (error) {
      console.error('Failed to initialize AI:', error);
    }
  }

  loadCommonPatterns() {
    return {
      acceptButtons: [
        // English
        'accept all', 'accept all cookies', 'allow all', 'agree', 'ok', 'got it',
        'i accept', 'continue', 'yes', 'accept and continue',
        // Spanish
        'aceptar todo', 'aceptar todas', 'acepto', 'continuar',
        // French
        'tout accepter', 'accepter tout', 'j\'accepte', 'continuer',
        // German
        'alle akzeptieren', 'akzeptieren', 'einverstanden', 'weiter',
        // Italian
        'accetta tutto', 'accetto', 'continua'
      ],
      rejectButtons: [
        // English
        'reject all', 'decline all', 'refuse', 'no thanks', 'deny',
        'reject all cookies', 'decline', 'no',
        // Spanish
        'rechazar todo', 'rechazar', 'no gracias', 'denegar',
        // French
        'tout refuser', 'refuser', 'non merci', 'décliner',
        // German
        'alle ablehnen', 'ablehnen', 'nein danke', 'verweigern',
        // Italian
        'rifiuta tutto', 'rifiuto', 'no grazie', 'nega'
      ],
      customizeButtons: [
        // English
        'customize', 'settings', 'preferences', 'manage cookies', 'cookie settings',
        'manage preferences', 'options', 'choose cookies', 'cookie preferences',
        // Spanish
        'personalizar', 'configuración', 'preferencias', 'gestionar cookies',
        // French
        'personnaliser', 'paramètres', 'préférences', 'gérer les cookies',
        // German
        'anpassen', 'einstellungen', 'präferenzen', 'cookies verwalten',
        // Italian
        'personalizza', 'impostazioni', 'preferenze', 'gestisci cookie'
      ],
      bannerIndicators: [
        'cookie', 'privacy', 'consent', 'gdpr', 'tracking', 'analytics',
        'advertisement', 'functional', 'essential', 'necessary'
      ]
    };
  }

  async analyzeBanner(bannerData) {
    await this.initialize();

    const analysis = {
      confidence: 0,
      language: 'en',
      buttons: {},
      recommendation: null,
      reasoning: ''
    };

    try {
      // Extract and analyze text content
      const text = bannerData.text.toLowerCase();
      const buttons = bannerData.buttons;

      // Detect language (simplified)
      analysis.language = this.detectLanguage(text);

      // Classify buttons
      for (const button of buttons) {
        const buttonText = button.text.toLowerCase().trim();
        analysis.buttons[button.text] = this.classifyButton(buttonText);
      }

      // Generate recommendation based on user preferences
      const userPrefs = await this.getUserPreferences();
      analysis.recommendation = this.generateRecommendation(analysis.buttons, userPrefs);
      analysis.confidence = this.calculateConfidence(analysis);
      analysis.reasoning = this.generateReasoning(analysis, userPrefs);

      return analysis;
    } catch (error) {
      console.error('Banner analysis failed:', error);
      return analysis;
    }
  }

  detectLanguage(text) {
    const langPatterns = {
      'fr': ['nous utilisons', 'cookies pour', 'confidentialité', 'accepter', 'refuser'],
      'es': ['utilizamos cookies', 'aceptar', 'rechazar', 'privacidad'],
      'de': ['wir verwenden', 'cookies', 'akzeptieren', 'ablehnen', 'datenschutz'],
      'it': ['utilizziamo cookie', 'accettare', 'rifiutare', 'privacy']
    };

    for (const [lang, patterns] of Object.entries(langPatterns)) {
      if (patterns.some(pattern => text.includes(pattern))) {
        return lang;
      }
    }
    return 'en';
  }

  classifyButton(buttonText) {
    if (this.commonPatterns.acceptButtons.some(pattern => 
        buttonText.includes(pattern) || pattern.includes(buttonText))) {
      return 'accept';
    }
    if (this.commonPatterns.rejectButtons.some(pattern => 
        buttonText.includes(pattern) || pattern.includes(buttonText))) {
      return 'reject';
    }
    if (this.commonPatterns.customizeButtons.some(pattern => 
        buttonText.includes(pattern) || pattern.includes(buttonText))) {
      return 'customize';
    }
    return 'unknown';
  }

  async getUserPreferences() {
    return new Promise((resolve) => {
      chrome.storage.sync.get({
        defaultAction: 'reject',
        autoHandle: true,
        delayMs: 1000,
        respectDNT: true,
        sitePref: {}
      }, resolve);
    });
  }

  generateRecommendation(buttons, userPrefs) {
    const hostname = new URL(chrome.runtime.getURL('/')).hostname;

    // Check site-specific preferences first
    if (userPrefs.sitePref[hostname]) {
      return userPrefs.sitePref[hostname];
    }

    // Apply default preference
    switch (userPrefs.defaultAction) {
      case 'accept':
        return Object.values(buttons).includes('accept') ? 'accept' : 'customize';
      case 'reject':
        return Object.values(buttons).includes('reject') ? 'reject' : 'customize';
      case 'essential':
        return 'customize';
      default:
        return 'reject';
    }
  }

  calculateConfidence(analysis) {
    let confidence = 0.5;

    // Increase confidence based on clear button classifications
    const classifiedButtons = Object.values(analysis.buttons).filter(type => type !== 'unknown');
    confidence += (classifiedButtons.length / Object.keys(analysis.buttons).length) * 0.3;

    // Increase confidence if we have both accept and reject options
    const buttonTypes = Object.values(analysis.buttons);
    if (buttonTypes.includes('accept') && buttonTypes.includes('reject')) {
      confidence += 0.2;
    }

    return Math.min(confidence, 1.0);
  }

  generateReasoning(analysis, userPrefs) {
    const action = analysis.recommendation;
    const buttonCount = Object.keys(analysis.buttons).length;

    let reasoning = `Detected ${buttonCount} button(s) in ${analysis.language}. `;
    reasoning += `User preference: ${userPrefs.defaultAction}. `;
    reasoning += `Recommended action: ${action} `;
    reasoning += `(confidence: ${(analysis.confidence * 100).toFixed(1)}%)`;

    return reasoning;
  }
}

// Initialize AI instance
const cookieAI = new CookieBannerAI();

// Message handling
chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  if (request.type === 'ANALYZE_BANNER') {
    cookieAI.analyzeBanner(request.data)
      .then(result => sendResponse({ success: true, analysis: result }))
      .catch(error => sendResponse({ success: false, error: error.message }));
    return true; // Keep message channel open for async response
  }

  if (request.type === 'GET_PREFERENCES') {
    cookieAI.getUserPreferences()
      .then(prefs => sendResponse({ success: true, preferences: prefs }))
      .catch(error => sendResponse({ success: false, error: error.message }));
    return true;
  }
});

