// content.js
class CookieBannerDetector {
  constructor() {
    this.processed = new Set();
    this.isEnabled = true;
    this.observer = null;
    this.init();
  }

  async init() {
    // Get user preferences
    const response = await chrome.runtime.sendMessage({ type: 'GET_PREFERENCES' });
    if (response.success && response.preferences.autoHandle) {
      this.startDetection();
    }
  }

  startDetection() {
    // Initial scan
    this.scanForBanners();

    // Set up mutation observer for dynamic content
    this.observer = new MutationObserver((mutations) => {
      let shouldScan = false;
      mutations.forEach(mutation => {
        if (mutation.type === 'childList' && mutation.addedNodes.length > 0) {
          shouldScan = true;
        }
      });
      if (shouldScan) {
        setTimeout(() => this.scanForBanners(), 500);
      }
    });

    this.observer.observe(document.body, {
      childList: true,
      subtree: true
    });
  }

  scanForBanners() {
    const potentialBanners = this.findPotentialBanners();

    potentialBanners.forEach(async (banner) => {
      const bannerId = this.getBannerId(banner);
      if (this.processed.has(bannerId)) return;

      this.processed.add(bannerId);
      await this.processBanner(banner);
    });
  }

  findPotentialBanners() {
    const selectors = [
      // Common cookie banner selectors
      '[id*="cookie"]', '[class*="cookie"]',
      '[id*="consent"]', '[class*="consent"]',
      '[id*="privacy"]', '[class*="privacy"]',
      '[id*="gdpr"]', '[class*="gdpr"]',
      '[id*="banner"]', '[class*="banner"]',
      // Common consent management platforms
      '#onetrust-banner-sdk',
      '.cookiebot',
      '[class*="CookieConsent"]',
      '[class*="cookie-consent"]',
      '[data-cookieconsent]',
      // Generic overlay/modal patterns
      '[role="dialog"]',
      '[role="banner"]',
      '.modal', '.overlay', '.popup'
    ];

    const elements = [];
    selectors.forEach(selector => {
      try {
        const found = document.querySelectorAll(selector);
        found.forEach(el => {
          if (this.isCookieBanner(el)) {
            elements.push(el);
          }
        });
      } catch (e) {
        // Ignore invalid selectors
      }
    });

    return [...new Set(elements)]; // Remove duplicates
  }

  isCookieBanner(element) {
    const text = element.textContent.toLowerCase();
    const cookieKeywords = [
      'cookie', 'privacy', 'consent', 'gdpr', 'tracking',
      'analytics', 'advertisement', 'functional', 'essential'
    ];

    const actionKeywords = [
      'accept', 'reject', 'decline', 'allow', 'deny',
      'agree', 'disagree', 'preferences', 'settings'
    ];

    const hasCookieKeywords = cookieKeywords.some(keyword => text.includes(keyword));
    const hasActionKeywords = actionKeywords.some(keyword => text.includes(keyword));
    const hasButtons = element.querySelectorAll('button, a, input[type="button"]').length > 0;

    // Must be visible and have reasonable size
    const rect = element.getBoundingClientRect();
    const isVisible = rect.width > 100 && rect.height > 50 && 
                     getComputedStyle(element).display !== 'none';

    return hasCookieKeywords && (hasActionKeywords || hasButtons) && isVisible;
  }

  getBannerId(element) {
    return element.id || element.className || element.tagName + '_' + 
           Array.from(element.parentNode.children).indexOf(element);
  }

  async processBanner(banner) {
    try {
      const bannerData = this.extractBannerData(banner);

      // Send to background for AI analysis
      const response = await chrome.runtime.sendMessage({
        type: 'ANALYZE_BANNER',
        data: bannerData
      });

      if (response.success) {
        await this.handleBannerBasedOnAnalysis(banner, response.analysis);
      }
    } catch (error) {
      console.error('Failed to process banner:', error);
    }
  }

  extractBannerData(banner) {
    const buttons = [];
    const buttonElements = banner.querySelectorAll('button, a[role="button"], input[type="button"], input[type="submit"]');

    buttonElements.forEach(btn => {
      if (btn.offsetParent !== null) { // Only visible buttons
        buttons.push({
          text: btn.textContent.trim() || btn.value || btn.title,
          element: btn
        });
      }
    });

    return {
      text: banner.textContent,
      buttons: buttons.map(b => ({ text: b.text })), // Don't send DOM elements to background
      url: window.location.href,
      timestamp: Date.now()
    };
  }

  async handleBannerBasedOnAnalysis(banner, analysis) {
    if (analysis.confidence < 0.7) {
      console.log('Low confidence analysis, skipping auto-handling');
      return;
    }

    const buttons = banner.querySelectorAll('button, a[role="button"], input[type="button"], input[type="submit"]');
    let targetButton = null;

    // Find the button that matches our recommendation
    for (const button of buttons) {
      const buttonText = button.textContent.trim().toLowerCase();
      const buttonClassification = this.classifyButtonLocally(buttonText);

      if ((analysis.recommendation === 'accept' && buttonClassification === 'accept') ||
          (analysis.recommendation === 'reject' && buttonClassification === 'reject') ||
          (analysis.recommendation === 'customize' && buttonClassification === 'customize')) {
        targetButton = button;
        break;
      }
    }

    if (targetButton) {
      // Add visual feedback
      this.highlightButton(targetButton);

      // Wait a moment, then click
      setTimeout(() => {
        console.log(`Auto-clicking: ${targetButton.textContent.trim()}`);
        targetButton.click();

        // Log the action
        this.logAction(analysis, targetButton.textContent.trim());
      }, 1000);
    }
  }

  classifyButtonLocally(buttonText) {
    // Simplified local classification for button matching
    const acceptWords = ['accept', 'allow', 'agree', 'ok', 'yes', 'continue'];
    const rejectWords = ['reject', 'decline', 'deny', 'no'];
    const customizeWords = ['customize', 'settings', 'preferences', 'manage', 'options'];

    if (acceptWords.some(word => buttonText.includes(word))) return 'accept';
    if (rejectWords.some(word => buttonText.includes(word))) return 'reject';
    if (customizeWords.some(word => buttonText.includes(word))) return 'customize';
    return 'unknown';
  }

  highlightButton(button) {
    const originalStyle = button.style.cssText;
    button.style.cssText += `
      outline: 3px solid #4CAF50 !important;
      outline-offset: 2px !important;
      box-shadow: 0 0 10px rgba(76, 175, 80, 0.5) !important;
    `;

    setTimeout(() => {
      button.style.cssText = originalStyle;
    }, 2000);
  }

  logAction(analysis, buttonText) {
    chrome.storage.local.get({ actionLog: [] }, (result) => {
      const log = result.actionLog;
      log.push({
        url: window.location.href,
        action: buttonText,
        confidence: analysis.confidence,
        timestamp: Date.now(),
        reasoning: analysis.reasoning
      });

      // Keep only last 100 entries
      if (log.length > 100) {
        log.splice(0, log.length - 100);
      }

      chrome.storage.local.set({ actionLog: log });
    });
  }
}

// Start detection when page loads
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => {
    new CookieBannerDetector();
  });
} else {
  new CookieBannerDetector();
}

