// popup.js
class PopupManager {
  constructor() {
    this.init();
  }

  async init() {
    await this.loadSettings();
    this.setupEventListeners();
    await this.updateStats();
  }

  async loadSettings() {
    const settings = await new Promise(resolve => {
      chrome.storage.sync.get({
        autoHandle: true,
        defaultAction: 'reject',
        delayMs: 1000,
        respectDNT: true
      }, resolve);
    });

    // Update UI with current settings
    document.getElementById('autoHandleToggle').classList.toggle('active', settings.autoHandle);
    document.getElementById('defaultAction').value = settings.defaultAction;
    document.getElementById('delayMs').value = settings.delayMs;
    document.getElementById('respectDNTToggle').classList.toggle('active', settings.respectDNT);

    // Update status indicator
    const indicator = document.getElementById('statusIndicator');
    indicator.className = `status-indicator ${settings.autoHandle ? 'status-active' : 'status-inactive'}`;
  }

  setupEventListeners() {
    // Auto-handle toggle
    document.getElementById('autoHandleToggle').addEventListener('click', () => {
      this.toggleSetting('autoHandle', 'autoHandleToggle');
    });

    // Respect DNT toggle  
    document.getElementById('respectDNTToggle').addEventListener('click', () => {
      this.toggleSetting('respectDNT', 'respectDNTToggle');
    });

    // Default action dropdown
    document.getElementById('defaultAction').addEventListener('change', (e) => {
      chrome.storage.sync.set({ defaultAction: e.target.value });
    });

    // Delay input
    document.getElementById('delayMs').addEventListener('change', (e) => {
      const value = Math.max(0, Math.min(5000, parseInt(e.target.value) || 1000));
      e.target.value = value;
      chrome.storage.sync.set({ delayMs: value });
    });

    // View log button
    document.getElementById('viewLogBtn').addEventListener('click', () => {
      chrome.tabs.create({ url: chrome.runtime.getURL('log.html') });
    });

    // Clear data button
    document.getElementById('clearDataBtn').addEventListener('click', () => {
      if (confirm('Clear all extension data? This cannot be undone.')) {
        chrome.storage.local.clear();
        chrome.storage.sync.clear();
        this.updateStats();
      }
    });
  }

  async toggleSetting(settingName, toggleId) {
    const current = await new Promise(resolve => {
      chrome.storage.sync.get({ [settingName]: false }, (result) => {
        resolve(result[settingName]);
      });
    });

    const newValue = !current;
    chrome.storage.sync.set({ [settingName]: newValue });

    document.getElementById(toggleId).classList.toggle('active', newValue);

    // Update status indicator for autoHandle
    if (settingName === 'autoHandle') {
      const indicator = document.getElementById('statusIndicator');
      indicator.className = `status-indicator ${newValue ? 'status-active' : 'status-inactive'}`;
    }
  }

  async updateStats() {
    const logs = await new Promise(resolve => {
      chrome.storage.local.get({ actionLog: [] }, (result) => {
        resolve(result.actionLog);
      });
    });

    const now = Date.now();
    const oneDayAgo = now - (24 * 60 * 60 * 1000);

    const dailyCount = logs.filter(log => log.timestamp > oneDayAgo).length;
    const totalCount = logs.length;
    const successCount = logs.filter(log => log.confidence > 0.7).length;
    const successRate = totalCount > 0 ? Math.round((successCount / totalCount) * 100) : 0;

    document.getElementById('dailyCount').textContent = dailyCount;
    document.getElementById('totalCount').textContent = totalCount;
    document.getElementById('successRate').textContent = `${successRate}%`;
  }
}

// Initialize popup when DOM is ready
document.addEventListener('DOMContentLoaded', () => {
  new PopupManager();
});

