    // Set default preferences
    await this.setDefaultPreferences();

    // Initialize site-specific settings
    await chrome.storage.local.set({
      siteSettings: {},
      extensionStats: {
        bannersHandled: 0,
        timesSaved: 0,
        installDate: Date.now()
      }
    });
  }

