      autoHandle: true,
      delay: 1000, // ms to wait before handling banner
      languages: ['en', 'fr', 'es', 'de'], // Supported languages
      enableLearning: true,
      showNotifications: true,
      logActivity: true
    };

    await chrome.storage.sync.set({ userPreferences: defaultPrefs });
  }

