    try {
      switch (message.type) {
        case 'ANALYZE_BANNER':
          const analysis = await this.analyzeBanner(message.data);
          sendResponse({ success: true, analysis });
          break;

        case 'BANNER_HANDLED':
          await this.recordBannerHandled(message.data);
          sendResponse({ success: true });
          break;

        case 'GET_SITE_PREFERENCE':
          const preference = await this.getSitePreference(message.domain);
          sendResponse({ success: true, preference });
          break;

        case 'UPDATE_STATS':
          await this.updateStats(message.data);
          sendResponse({ success: true });
          break;

        default:
          sendResponse({ success: false, error: 'Unknown message type' });
      }
    } catch (error) {
      console.error('Background service error:', error);
      sendResponse({ success: false, error: error.message });
    }
  }

  async analyzeBanner(bannerData) {
    // This would integrate with AI service
    // For now, using rule-based analysis as fallback

    const analysis = {
