      language: this.detectLanguage(bannerData.text),
      bannerType: this.classifyBanner(bannerData),
      buttons: this.classifyButtons(bannerData.buttons),
      recommendation: await this.getRecommendation(bannerData)
    };

    return analysis;
  }

  detectLanguage(text) {
    // Simple language detection
    const patterns = {
      en: /cookies?|privacy|consent|accept|reject/i,
      fr: /cookies?|confidentialité|accepter|refuser/i,
      es: /cookies?|privacidad|aceptar|rechazar/i,
      de: /cookies?|datenschutz|akzeptieren|ablehnen/i
    };

    for (const [lang, pattern] of Object.entries(patterns)) {
      if (pattern.test(text)) return lang;
    }
    return 'en'; // Default
  }

