    const text = bannerData.text.toLowerCase();

    if (text.includes('essential') || text.includes('necessary')) {
      return 'detailed-categories';
    } else if (text.includes('gdpr') || text.includes('privacy')) {
      return 'privacy-focused';
    } else {
      return 'standard';
