// Main content script coordinator

class CookieHandlerCoordinator {
  constructor() {
    this.isEnabled = true;
    this.processingBanner = false;
    this.handledBanners = new Set();

    this.init();
  }

  async init() {
    console.log('Smart Cookie Handler initialized on:', window.location.hostname);

    // Load user preferences
    await this.loadPreferences();

    // Set up observers
    this.setupObservers();

    // Initial scan
    setTimeout(() => this.scanAndHandle(), 1000);
  }

  async loadPreferences() {
    try {
      const result = await chrome.storage.sync.get('userPreferences');
      this.preferences = result.userPreferences || {};

      // Get site-specific preferences
      const siteResult = await chrome.runtime.sendMessage({
        type: 'GET_SITE_PREFERENCE',
        domain: window.location.hostname
      });

      if (siteResult.success && siteResult.preference) {
        this.sitePreference = siteResult.preference;
      }
    } catch (error) {
      console.error('Failed to load preferences:', error);
      this.preferences = { globalPreference: 'reject-all', autoHandle: true };
    }
  }

  setupObservers() {
    // Watch for DOM changes to catch dynamically loaded banners
    this.observer = new MutationObserver((mutations) => {
      let shouldScan = false;

      mutations.forEach(mutation => {
        if (mutation.type === 'childList' && mutation.addedNodes.length > 0) {
          // Check if any added nodes might be cookie banners
          mutation.addedNodes.forEach(node => {
            if (node.nodeType === Node.ELEMENT_NODE) {
              const text = node.textContent?.toLowerCase() || '';
              if (text.includes('cookie') || text.includes('privacy') || text.includes('consent')) {
                shouldScan = true;
              }
            }
          });
        }
      });

      if (shouldScan && !this.processingBanner) {
        setTimeout(() => this.scanAndHandle(), 500);
      }
    });

    this.observer.observe(document.body, {
      childList: true,
      subtree: true
    });

    // Listen for preference changes
    chrome.storage.onChanged.addListener((changes, namespace) => {
      if (namespace === 'sync' && changes.userPreferences) {
        this.preferences = changes.userPreferences.newValue;
      }
    });
  }

  async scanAndHandle() {
    if (!this.isEnabled || this.processingBanner) return;

    this.processingBanner = true;

    try {
      // Detect cookie banners
      const banners = window.cookieBannerDetector.detectBanners();

      for (const banner of banners) {
        const bannerId = this.getBannerId(banner.element);

        if (this.handledBanners.has(bannerId)) continue;

        // Analyze banner with AI
        const analysis = await this.analyzeBanner(banner);

        if (analysis.confidence > 0.7) {
          await this.handleBanner(banner, analysis);
          this.handledBanners.add(bannerId);
        }
      }
    } catch (error) {
      console.error('Error scanning for banners:', error);
    } finally {
      this.processingBanner = false;
    }
  }

  getBannerId(element) {
    // Create unique ID for banner element
    return element.id || 
           element.className || 
           element.outerHTML.substring(0, 100);
  }

  async analyzeBanner(banner) {
    try {
      const bannerData = {
        text: banner.text,
        buttons: banner.buttons,
        element: banner.element.outerHTML.substring(0, 1000),
        url: window.location.href
      };

      const response = await chrome.runtime.sendMessage({
        type: 'ANALYZE_BANNER',
        data: bannerData
      });

      return response.success ? response.analysis : null;
    } catch (error) {
      console.error('Banner analysis failed:', error);
      return null;
    }
  }

  async handleBanner(banner, analysis) {
    if (!this.preferences.autoHandle) return;

    const action = this.sitePreference || this.preferences.globalPreference;
    const button = this.findTargetButton(banner.buttons, analysis.buttons, action);

    if (button) {
      // Add delay to appear more natural
      setTimeout(() => {
        this.clickButton(button, banner);
      }, this.preferences.delay || 1000);
    }
  }

  findTargetButton(buttons, classifications, desiredAction) {
    // Map user preference to button classification
    const actionMap = {
      'accept-all': 'accept-all',
      'reject-all': 'reject-all', 
      'essential-only': 'essential-only',
      'ask-each-time': null // Don't auto-handle
    };

    const targetClassification = actionMap[desiredAction];
    if (!targetClassification) return null;

    // Find button with matching classification
    for (const button of buttons) {
      const buttonId = button.id || button.textContent;
      if (classifications[buttonId] === targetClassification) {
        return button;
      }
    }

    // Fallback: try to find by text content
    const fallbackPatterns = {
      'accept-all': /accept.*all|allow.*all|agree/i,
      'reject-all': /reject.*all|decline.*all|refuse/i,
      'essential-only': /essential|necessary/i
    };

    const pattern = fallbackPatterns[targetClassification];
    if (pattern) {
      return buttons.find(btn => pattern.test(btn.textContent || ''));
    }

    return null;
  }

  clickButton(button, banner) {
    try {
      // Scroll button into view if needed
      button.scrollIntoView({ behavior: 'smooth', block: 'center' });

      // Simulate human-like click
      setTimeout(() => {
        // Try multiple click methods for compatibility
        if (button.click) {
          button.click();
        } else {
          // Create and dispatch click event
          const event = new MouseEvent('click', {
            bubbles: true,
            cancelable: true,
            view: window
          });
          button.dispatchEvent(event);
        }

        // Record successful handling
        this.recordSuccess(banner);

        console.log('Cookie banner handled:', button.textContent);
      }, 200);

    } catch (error) {
      console.error('Failed to click button:', error);
    }
  }

  async recordSuccess(banner) {
    try {
      await chrome.runtime.sendMessage({
        type: 'BANNER_HANDLED',
        data: {
          domain: window.location.hostname,
          url: window.location.href,
          timestamp: Date.now(),
          timeSaved: 3 // Estimated seconds saved
        }
      });
    } catch (error) {
      console.error('Failed to record success:', error);
    }
  }

  // Public methods for testing and manual control
  disable() {
    this.isEnabled = false;
    if (this.observer) {
      this.observer.disconnect();
    }
  }

  enable() {
    this.isEnabled = true;
    this.setupObservers();
  }

  manualScan() {
    return this.scanAndHandle();
  }
}

// Initialize when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => {
    window.cookieHandlerCoordinator = new CookieHandlerCoordinator();
  });
} else {
  window.cookieHandlerCoordinator = new CookieHandlerCoordinator();
}
